package com.example.energymonitoringapp.ui.navigation

import android.window.SplashScreen
import androidx.compose.runtime.Composable
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import com.example.energymonitoringapp.ui.screen.admin.dashboard.dashboardAdminScreen
import com.example.energymonitoringapp.ui.screen.admin.login.LoginAdminScreen
import com.example.energymonitoringapp.ui.screen.admin.notifikasi.detailNotifAdminScreen
import com.example.energymonitoringapp.ui.screen.admin.notifikasi.notifikasiAdminScreen
import com.example.energymonitoringapp.ui.screen.admin.pemantauan.pemantauanScreen
import com.example.energymonitoringapp.ui.screen.common.pengaturan.EditProfilFormScreen
import com.example.energymonitoringapp.ui.screen.common.pengaturan.batasnilaiParameterScreen
import com.example.energymonitoringapp.ui.screen.common.pengaturan.editProfilScreen
import com.example.energymonitoringapp.ui.screen.common.pengaturan.pengaturanAdminScreen
import com.example.energymonitoringapp.ui.screen.common.pengaturan.pengaturanScreen
import com.example.energymonitoringapp.ui.screen.common.pengaturan.ubahPasswordScreen
import com.example.energymonitoringapp.ui.screen.common.splash.splashScreen
import com.example.energymonitoringapp.ui.screen.teknisi.dashboard.dashboardScreen
import com.example.energymonitoringapp.ui.screen.teknisi.login.LoginTeknisiScreen
import com.example.energymonitoringapp.ui.screen.teknisi.notifikasi.detailNotifScreen
import com.example.energymonitoringapp.ui.screen.teknisi.notifikasi.konfirmasiPenangananScreen
import com.example.energymonitoringapp.ui.screen.teknisi.notifikasi.notifikasiScreen

// ─── Semua route string ───────────────────────────────────────
object Routes {
    // Common
    const val SPLASH            = "splash"
    const val UBAH_PASSWORD     = "ubah_password"
    const val EDIT_PROFIL       = "edit_profil"
    const val EDIT_PROFIL_FORM  = "edit_profil_form"
    const val BATAS_NILAI       = "batas_nilai"
    const val PENGATURAN_TEKNISI    = "pengaturan_teknisi"
    const val PENGATURAN_ADMIN   = "pengaturan_admin"

    // Teknisi
    const val LOGIN_TEKNISI         = "login_teknisi"
    const val DASHBOARD_TEKNISI     = "dashboard_teknisi"
    const val NOTIFIKASI_TEKNISI    = "notifikasi_teknisi"
    const val DETAIL_NOTIF_TEKNISI  = "detail_notif_teknisi/{notifId}"
    const val KONFIRMASI_PENANGANAN = "konfirmasi_penanganan"

    // Admin
    const val LOGIN_ADMIN        = "login_admin"
    const val DASHBOARD_ADMIN    = "dashboard_admin"
    const val PEMANTAUAN_ADMIN   = "pemantauan_admin"
    const val NOTIFIKASI_ADMIN   = "notifikasi_admin"
    const val DETAIL_NOTIF_ADMIN = "detail_notif_admin/{notifId}"

    // Helper fungsi untuk route dengan argumen
    fun detailNotifTeknisi(notifId: Int) = "detail_notif_teknisi/$notifId"
    fun detailNotifAdmin(notifId: Int)   = "detail_notif_admin/$notifId"
}

// ─── NavGraph utama ───────────────────────────────────────────
@Composable
fun AppNavigation() {
    val navController = rememberNavController()

    NavHost(
        navController    = navController,
        startDestination = Routes.SPLASH
    ) {

        // ══════════════════════════════════════════════════════
        // COMMON — dipakai kedua role
        // ══════════════════════════════════════════════════════

        // Splash: pilih role Admin atau Teknisi
        composable(Routes.SPLASH) {
            splashScreen(
                onAdminClick   = { navController.navigate(Routes.LOGIN_ADMIN) },
                onTeknisiClick = { navController.navigate(Routes.LOGIN_TEKNISI) }
            )
        }

        // Login Teknisi → Dashboard Teknisi
        // popUpTo LOGIN_TEKNISI inclusive = true → login dihapus dari back stack
        // sehingga tombol back dari dashboard tidak kembali ke login
        composable(Routes.LOGIN_TEKNISI) {
            LoginTeknisiScreen(
                onLoginSuccess = {
                    navController.navigate(Routes.DASHBOARD_TEKNISI) {
                        popUpTo(Routes.LOGIN_TEKNISI) { inclusive = true }
                    }
                },
                onBackClick = { navController.popBackStack() }
            )
        }

        // Login Admin → Dashboard Admin
        composable(Routes.LOGIN_ADMIN) {
            LoginAdminScreen(
                onLoginSuccess = {
                    navController.navigate(Routes.DASHBOARD_ADMIN) {
                        popUpTo(Routes.LOGIN_ADMIN) { inclusive = true }
                    }
                },
                onBackClick = { navController.popBackStack() }
            )
        }

        // Ubah Password — shared kedua role
        // onSaveSuccess: setelah dialog "berhasil" → OK → popBackStack ke Pengaturan
        composable(Routes.UBAH_PASSWORD) {
            ubahPasswordScreen(
                onBackClick   = { navController.popBackStack() },
                onSaveSuccess = { navController.popBackStack() }
            )
        }

        // Edit Profil view — shared
        composable(Routes.EDIT_PROFIL) {
            editProfilScreen(
                onBackClick = { navController.popBackStack() },
                onEditClick = { navController.navigate(Routes.EDIT_PROFIL_FORM) }
            )
        }

        // Edit Profil form — shared
        // onSaveSuccess: setelah dialog "berhasil" → OK → kembali ke view profil
        composable(Routes.EDIT_PROFIL_FORM) {
            EditProfilFormScreen(
                onBackClick   = { navController.popBackStack() },
                onSaveSuccess = { navController.popBackStack() }
            )
        }

        // Batas Nilai Parameter — shared
        composable(Routes.BATAS_NILAI) {
            batasnilaiParameterScreen(
                onBackClick = { navController.popBackStack() }
            )
        }

        // ══════════════════════════════════════════════════════
        // TEKNISI FLOW
        //
        // Splash → Login Teknisi → Dashboard Teknisi
        // Bottom nav: Dashboard | Notifikasi | Pengaturan
        //
        // Dashboard → (bottom nav) → Notifikasi
        // Notifikasi → klik item → Detail Notif
        // Detail Notif → Konfirmasi Penanganan → OK → Notifikasi
        // Pengaturan → Ubah Password / Edit Profil / Batas Nilai
        // Pengaturan → Keluar → dialog → OK → Splash (clear all)
        // ══════════════════════════════════════════════════════

        // T-1. Dashboard Teknisi
        composable(Routes.DASHBOARD_TEKNISI) {
            dashboardScreen(
                onNotifikasiClick = { navController.navigate(Routes.NOTIFIKASI_TEKNISI) },
                onPengaturanClick = { navController.navigate(Routes.PENGATURAN_TEKNISI) }
            )
        }

        // T-2. Notifikasi Teknisi
        composable(Routes.NOTIFIKASI_TEKNISI) {
            notifikasiScreen(
                // Bottom nav
                onDashboardClick  = {
                    navController.navigate(Routes.DASHBOARD_TEKNISI) {
                        popUpTo(Routes.DASHBOARD_TEKNISI) { inclusive = false }
                    }
                },
                onPengaturanClick = { navController.navigate(Routes.PENGATURAN_TEKNISI) },
                // Klik salah satu item notifikasi
                onNotifClick = { notifId ->
                    navController.navigate(Routes.detailNotifTeknisi(notifId))
                }
            )
        }

        // T-3. Detail Notif Teknisi
        // Menerima notifId dari route argument
        composable(Routes.DETAIL_NOTIF_TEKNISI) { backStackEntry ->
            val notifId = backStackEntry.arguments?.getString("notifId")?.toIntOrNull() ?: 0
            detailNotifScreen(
                notifId           = notifId,
                onBackClick       = { navController.popBackStack() },
                onKonfirmasiClick = { navController.navigate(Routes.KONFIRMASI_PENANGANAN) }
            )
        }

        // T-4. Konfirmasi Penanganan
        // Setelah klik OK pada dialog:
        // pop semua screen sampai Notifikasi (konfirmasi + detail terhapus dari stack)
        composable(Routes.KONFIRMASI_PENANGANAN) {
            konfirmasiPenangananScreen(
                onBackClick    = { navController.popBackStack() },
                onKirimSuccess = {
                    navController.navigate(Routes.NOTIFIKASI_TEKNISI) {
                        popUpTo(Routes.NOTIFIKASI_TEKNISI) { inclusive = false }
                    }
                }
            )
        }

        // T-5. Pengaturan Teknisi
        composable(Routes.PENGATURAN_TEKNISI) {
            pengaturanScreen(
                // Bottom nav
                onDashboardClick  = {
                    navController.navigate(Routes.DASHBOARD_TEKNISI) {
                        popUpTo(Routes.DASHBOARD_TEKNISI) { inclusive = false }
                    }
                },
                onNotifikasiClick = {
                    navController.navigate(Routes.NOTIFIKASI_TEKNISI) {
                        popUpTo(Routes.NOTIFIKASI_TEKNISI) { inclusive = false }
                    }
                },
                // Menu items
                onUbahPasswordClick = { navController.navigate(Routes.UBAH_PASSWORD) },
                onEditProfilClick   = { navController.navigate(Routes.EDIT_PROFIL) },
                onBatasNilaiClick   = { navController.navigate(Routes.BATAS_NILAI) },
                // Keluar: dialog muncul di dalam PengaturanTeknisiScreen,
                // setelah klik OK, panggil lambda ini → clear semua back stack → Splash
                onKeluarConfirmed   = {
                    navController.navigate(Routes.SPLASH) {
                        popUpTo(0) { inclusive = true }
                    }
                }
            )
        }

        // ══════════════════════════════════════════════════════
        // ADMIN FLOW
        //
        // Splash → Login Admin → Dashboard Admin
        // Bottom nav: Dashboard | Pemantauan | Notifikasi | Pengaturan
        //
        // Dashboard → Pemantauan
        // Dashboard → Notifikasi → klik item → Detail Notif
        // Detail Notif → "Kirim ke Teknisi" → dialog popup → OK → kembali ke Notifikasi
        // Pengaturan → Ubah Password / Edit Profil / Batas Nilai
        // Pengaturan → Keluar → dialog → OK → Splash (clear all)
        // ══════════════════════════════════════════════════════

        // A-1. Dashboard Admin
        composable(Routes.DASHBOARD_ADMIN) {
            dashboardAdminScreen(
                onPemantauanClick = { navController.navigate(Routes.PEMANTAUAN_ADMIN) },
                onNotifikasiClick = { navController.navigate(Routes.NOTIFIKASI_ADMIN) },
                onPengaturanClick = { navController.navigate(Routes.PENGATURAN_ADMIN) }
            )
        }

        // A-2. Pemantauan Admin
        composable(Routes.PEMANTAUAN_ADMIN) {
            pemantauanScreen(
                onDashboardClick  = {
                    navController.navigate(Routes.DASHBOARD_ADMIN) {
                        popUpTo(Routes.DASHBOARD_ADMIN) { inclusive = false }
                    }
                },
                onNotifikasiClick = { navController.navigate(Routes.NOTIFIKASI_ADMIN) },
                onPengaturanClick = { navController.navigate(Routes.PENGATURAN_ADMIN) }
            )
        }

        // A-3. Notifikasi Admin
        composable(Routes.NOTIFIKASI_ADMIN) {
            notifikasiAdminScreen(
                // Bottom nav
                onDashboardClick  = {
                    navController.navigate(Routes.DASHBOARD_ADMIN) {
                        popUpTo(Routes.DASHBOARD_ADMIN) { inclusive = false }
                    }
                },
                onPemantauanClick = { navController.navigate(Routes.PEMANTAUAN_ADMIN) },
                onPengaturanClick = { navController.navigate(Routes.PENGATURAN_ADMIN) },
                // Klik item notifikasi
                onNotifClick = { notifId ->
                    navController.navigate(Routes.detailNotifAdmin(notifId))
                }
            )
        }

        // A-4. Detail Notif Admin
        // Tombol "Kirim ke Teknisi" → tampilkan AlertDialog di dalam screen ini
        // Setelah OK pada dialog → onKirimSuccess → kembali ke Notifikasi Admin
        composable(Routes.DETAIL_NOTIF_ADMIN) { backStackEntry ->
            val notifId = backStackEntry.arguments?.getString("notifId")?.toIntOrNull() ?: 0
            detailNotifAdminScreen(
                notifId        = notifId,
                onBackClick    = { navController.popBackStack() },
                onKirimSuccess = {
                    navController.navigate(Routes.NOTIFIKASI_ADMIN) {
                        popUpTo(Routes.NOTIFIKASI_ADMIN) { inclusive = false }
                    }
                }
            )
        }

        // A-5. Pengaturan Admin
        composable(Routes.PENGATURAN_ADMIN) {
            pengaturanAdminScreen(
                // Bottom nav
                onDashboardClick  = {
                    navController.navigate(Routes.DASHBOARD_ADMIN) {
                        popUpTo(Routes.DASHBOARD_ADMIN) { inclusive = false }
                    }
                },
                onPemantauanClick = { navController.navigate(Routes.PEMANTAUAN_ADMIN) },
                onNotifikasiClick = { navController.navigate(Routes.NOTIFIKASI_ADMIN) },
                // Menu items
                onUbahPasswordClick = { navController.navigate(Routes.UBAH_PASSWORD) },
                onEditProfilClick   = { navController.navigate(Routes.EDIT_PROFIL) },
                onBatasNilaiClick   = { navController.navigate(Routes.BATAS_NILAI) },
                // Keluar: clear semua → Splash
                onKeluarConfirmed   = {
                    navController.navigate(Routes.SPLASH) {
                        popUpTo(0) { inclusive = true }
                    }
                }
            )
        }
    }
}

package com.example.energymonitoringapp.ui.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
