import com.example.energymonitoringapp.ui.theme.OrangeLight
import com.example.energymonitoringapp.ui.theme.OrangePrimary
import com.example.energymonitoringapp.ui.theme.RedLight
import com.example.energymonitoringapp.ui.theme.RedPrimary
import com.example.energymonitoringapp.ui.theme.TextPrimary
import com.example.energymonitoringapp.ui.theme.TextSecondary
