// ─── Enum for legacy compatibility ──────────────────────────
enum class NotifLevel { BAHAYA, WASPADA }
enum class NotifStatus { AKTIF, SELESAI }
enum class KategoriType { LISTRIK, LINGKUNGAN }

// ─── Screen ───────────────────────────────────────────────────
@Composable
fun notifikasiScreen(
    onNavigateTo: (String) -> Unit = {},
    // Klik item notifikasi
    onNotifClick: (Int) -> Unit = {}
) {
    var selectedTab by remember { mutableIntStateOf(0) }
    var bottomTab   by remember { mutableIntStateOf(1) }

    val filtered = remember(selectedTab) {
        when (selectedTab) {
            1    -> sampleNotifikasi.filter { it.status == NotifStatus.AKTIF }
            2    -> sampleNotifikasi.filter { it.status == NotifStatus.SELESAI }
            else -> sampleNotifikasi
        }
    }

    Scaffold(
        containerColor = White,
        bottomBar = {
            TeknisiBottomNavBar(
                selectedTab       = bottomTab,
                onTabSelected     = { bottomTab = it },
                onNavigateTo = onNavigateTo
            )
        }
    ) { innerPadding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
        ) {
            Text(
                text = "Notifikasi",
                fontWeight = FontWeight.Bold,
                fontSize = 20.sp,
                color = TextPrimary,
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(top = 20.dp, bottom = 16.dp),
                textAlign = androidx.compose.ui.text.style.TextAlign.Center
            )

            FilterTabRow(
                selectedTab = selectedTab,
                onTabSelected = { selectedTab = it }
            )

            Spacer(modifier = Modifier.height(16.dp))

            LazyColumn(
                contentPadding = PaddingValues(horizontal = 16.dp, vertical = 4.dp),
                verticalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                items(filtered) { item ->
                    NotifCard(
                        item = item,
                        onClick = { onNotifClick(item.id) }  // tambah onClick
                    )
                }
                item { Spacer(modifier = Modifier.height(8.dp)) }
            }
        }
    }
}

// ─── Tab Aktif / Selesai ──────────────────────────────────────
@Composable
fun FilterTabRow(selectedTab: Int, onTabSelected: (Int) -> Unit) {
    val tabs = listOf("Aktif", "Selesai")
    val tabIndices = listOf(1, 2)

    Row(
        modifier = Modifier
            .padding(horizontal = 16.dp)
            .fillMaxWidth()
            .clip(RoundedCornerShape(8.dp))
            .border(1.dp, BorderGray, RoundedCornerShape(8.dp))
    ) {
        tabs.forEachIndexed { i, label ->
            val tabIndex      = tabIndices[i]
            val isSelected    = selectedTab == tabIndex
            val bgColor       = if (isSelected) GreenLight else White
            val textColor     = if (isSelected) GreenDark  else TextSecondary
            val interactionSource = remember { MutableInteractionSource() }  // ← tambah ini

            Box(
                modifier = Modifier
                    .weight(1f)
                    .clip(RoundedCornerShape(8.dp))
                    .background(bgColor)
                    .clickable(                           // ← ganti clickable
                        interactionSource = interactionSource,
                        indication        = null
                    ) { onTabSelected(tabIndex) }
                    .padding(vertical = 8.dp),
                contentAlignment = Alignment.Center
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.Center
                ) {
                    if (isSelected) {
                        Icon(
                            imageVector        = Icons.Default.Check,
                            contentDescription = null,
                            tint               = GreenDark,
                            modifier           = Modifier.size(14.dp)
                        )
                        Spacer(modifier = Modifier.width(4.dp))
                    }
                    Text(
                        text       = label,
                        color      = textColor,
                        fontWeight = if (isSelected) FontWeight.SemiBold else FontWeight.Normal,
                        fontSize   = 14.sp
                    )
                }
            }
        }
    }
}


@Composable
fun NotifCard(item: NotifikasiItem, onClick: () -> Unit = {}) {
    val (leftBarColor, bgColor, badgeColor, badgeTint) = when {
        item.level == NotifLevel.BAHAYA && item.status == NotifStatus.AKTIF ->
            listOf(RedPrimary, RedLight.copy(alpha = 0.4f), RedPrimary, White)
        item.level == NotifLevel.BAHAYA && item.status == NotifStatus.SELESAI ->
            listOf(GreenTeal, GreenLight.copy(alpha = 0.4f), GreenTeal, White)
        item.level == NotifLevel.WASPADA ->
            listOf(OrangePrimary, OrangeLight.copy(alpha = 0.5f), OrangePrimary, White)
        else ->
            listOf(BorderGray, White, BorderGray, TextSecondary)
    }

    val levelIconTint = when {
        item.level == NotifLevel.BAHAYA && item.status == NotifStatus.AKTIF   -> RedPrimary
        item.level == NotifLevel.BAHAYA && item.status == NotifStatus.SELESAI -> GreenTeal
        else                                                                   -> OrangePrimary
    }
    val levelText    = if (item.level == NotifLevel.BAHAYA) "Bahaya" else "Waspada"
    val badgeText    = if (item.status == NotifStatus.AKTIF) "Aktif" else "Selesai"
    val kategoriIcon = painterResource(id = if (item.kategori == KategoriType.LISTRIK)
        R.drawable.baseline_bolt_24 else R.drawable.outline_eco_24)
    val kategoriLabel = if (item.kategori == KategoriType.LISTRIK) "Listrik" else "Lingkungan"

    Card(
        onClick  = { onClick() },              // ← pindah ke parameter onClick Card
        modifier = Modifier.fillMaxWidth(),    // ← hapus .clickable dari sini
        shape    = RoundedCornerShape(12.dp),
        colors   = CardDefaults.cardColors(containerColor = White),
        elevation = CardDefaults.cardElevation(defaultElevation = 1.dp),
        border    = BorderStroke(1.dp, BorderGray)
    ) {
        Row(modifier = Modifier.fillMaxWidth()) {
            // Garis kiri berwarna
            Box(
                modifier = Modifier
                    .width(6.dp)
                    .fillMaxHeight()
                    .background(
                        color = leftBarColor,
                        shape = RoundedCornerShape(topStart = 12.dp, bottomStart = 12.dp)
                    )
                    .defaultMinSize(minHeight = 165.dp)
            )

            // Konten
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(bgColor)
                    .padding(horizontal = 12.dp, vertical = 10.dp)
            ) {
                // Baris atas: level + badge
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(
                            imageVector        = Icons.Default.Warning,
                            contentDescription = null,
                            tint               = levelIconTint,
                            modifier           = Modifier.size(18.dp)
                        )
                        Spacer(modifier = Modifier.width(6.dp))
                        Text(
                            text       = levelText,
                            fontWeight = FontWeight.Bold,
                            fontSize   = 15.sp,
                            color      = TextPrimary
                        )
                    }
                    // Badge status
                    Box(
                        modifier = Modifier
                            .clip(RoundedCornerShape(6.dp))
                            .background(badgeColor)
                            .padding(horizontal = 10.dp, vertical = 3.dp)
                    ) {
                        Text(
                            text       = badgeText,
                            color      = badgeTint,
                            fontSize   = 12.sp,
                            fontWeight = FontWeight.SemiBold
                        )
                    }
                }

                Spacer(modifier = Modifier.height(4.dp))

                // Kategori
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Icon(
                        painter        = kategoriIcon,
                        contentDescription = null,
                        tint               = TextSecondary,
                        modifier           = Modifier.size(14.dp)
                    )
                    Spacer(modifier = Modifier.width(4.dp))
                    Text(text = kategoriLabel, fontSize = 13.sp, color = TextSecondary)
                }

                Spacer(modifier = Modifier.height(6.dp))

                // Pesan
                Text(text = item.pesan, fontSize = 13.sp, color = TextPrimary)

                Spacer(modifier = Modifier.height(6.dp))

                // Lokasi
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Icon(
                        imageVector        = Icons.Default.LocationOn,
                        contentDescription = null,
                        tint               = TextSecondary,
                        modifier           = Modifier.size(13.dp)
                    )
                    Spacer(modifier = Modifier.width(3.dp))
                    Text(text = item.lokasi, fontSize = 12.sp, color = TextSecondary)
                }

                Spacer(modifier = Modifier.height(3.dp))

                // Waktu
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Icon(
                        painter        = painterResource(id=R.drawable.baseline_access_time_24),
                        contentDescription = null,
                        tint               = TextSecondary,
                        modifier           = Modifier.size(13.dp)
                    )
                    Spacer(modifier = Modifier.width(3.dp))
                    Text(text = item.waktu, fontSize = 12.sp, color = TextSecondary)
                }
            }
        }
    }
}


